using Microsoft.VisualStudio.TestTools.UnitTesting;
using ContosoUniversity.Models;
using System;

namespace ContosoUniversity.Tests.Models;

[TestClass]
public sealed class PersonTests
{
    [TestMethod]
    public void FullName_WithLastAndFirstName_ReturnsCommaFormatted()
    {
        // Arrange
        var student = new Student { LastName = "Smith", FirstMidName = "John" };

        // Act
        var result = student.FullName;

        // Assert
        Assert.AreEqual("Smith, John", result);
    }

    [TestMethod]
    public void FullName_WithDifferentNames_ReturnsCorrectFormat()
    {
        // Arrange
        var instructor = new Instructor { LastName = "Doe", FirstMidName = "Jane" };

        // Act
        var result = instructor.FullName;

        // Assert
        Assert.AreEqual("Doe, Jane", result);
    }

    [TestMethod]
    [DataRow("Alexander", "Carson", "Alexander, Carson")]
    [DataRow("Li", "Yan", "Li, Yan")]
    [DataRow("O'Brien", "Mary", "O'Brien, Mary")]
    public void FullName_VariousInputs_ReturnsExpectedFormat(string lastName, string firstName, string expected)
    {
        // Arrange
        var student = new Student { LastName = lastName, FirstMidName = firstName };

        // Act
        var result = student.FullName;

        // Assert
        Assert.AreEqual(expected, result);
    }

    [TestMethod]
    public void Student_EnrollmentDate_CanBeSet()
    {
        // Arrange
        var date = new DateTime(2023, 9, 1);
        var student = new Student { EnrollmentDate = date };

        // Assert
