using Microsoft.VisualStudio.TestTools.UnitTesting;
using ContosoUniversity.Services;
using ContosoUniversity.Models;
using System;
using System.Reflection;
using System.Collections.Concurrent;

namespace ContosoUniversity.Tests.Services;

[TestClass]
public sealed class NotificationServiceTests
{
    private NotificationService _service = null!;

    [TestInitialize]
    public void Setup()
    {
        _service = new NotificationService();
        // Drain the static queue to avoid cross-test pollution
        DrainQueue();
    }

    [TestCleanup]
    public void Cleanup()
    {
        DrainQueue();
        _service.Dispose();
    }

    private void DrainQueue()
    {
        // Drain by receiving until empty
        while (_service.ReceiveNotification() != null) { }
    }

    [TestMethod]
    public void SendNotification_WithoutDisplayName_EnqueuesNotification()
    {
        // Act
        _service.SendNotification("Student", "1", EntityOperation.CREATE);
        var notification = _service.ReceiveNotification();

        // Assert
        Assert.IsNotNull(notification);
        Assert.AreEqual("Student", notification.EntityType);
        Assert.AreEqual("1", notification.EntityId);
        Assert.AreEqual("CREATE", notification.Operation);
        Assert.IsFalse(notification.IsRead);
    }

    [TestMethod]
    public void SendNotification_WithDisplayName_EnqueuesNotificationWithDisplayName()
    {
        // Act
        _service.SendNotification("Student", "1", "John Doe", EntityOperation.CREATE);
        var notification = _service.ReceiveNotification();

        // Assert
        Assert.IsNotNull(notification);
        Assert.AreEqual("Student", notification.EntityType);
        Assert.AreEqual("1", notification.EntityId);
        Assert.AreEqual("CREATE", notification.Operation);
        Assert.IsTrue(notification.Message.Contains("John Doe"));
    }

    [TestMethod]
    public void SendNotification_WithUserName_SetsCreatedBy()
    {
        // Act
        _service.SendNotification("Course", "101", EntityOperation.UPDATE, "admin");
        var notification = _service.ReceiveNotification();

        // Assert
        Assert.IsNotNull(notification);
        Assert.AreEqual("admin", notification.CreatedBy);
    }

    [TestMethod]
    public void SendNotification_WithoutUserName_DefaultsToSystem()
    {
        // Act
        _service.SendNotification("Course", "101", EntityOperation.UPDATE);
        var notification = _service.ReceiveNotification();

        // Assert
        Assert.IsNotNull(notification);
        Assert.AreEqual("System", notification.CreatedBy);
    }

    [TestMethod]
    public void SendNotification_SetsCreatedAtToCurrentTime()
    {
        // Act
        var before = DateTime.Now;
        _service.SendNotification("Student", "1", EntityOperation.CREATE);
        var after = DateTime.Now;
        var notification = _service.ReceiveNotification();

        // Assert
        Assert.IsNotNull(notification);
        Assert.IsTrue(notification.CreatedAt >= before && notification.CreatedAt <= after);
    }

    [TestMethod]
    public void SendNotification_IsReadIsFalse()
    {
        // Act
        _service.SendNotification("Student", "1", EntityOperation.CREATE);
        var notification = _service.ReceiveNotification();

        // Assert
        Assert.IsNotNull(notification);
        Assert.IsFalse(notification.IsRead);
    }

    [TestMethod]
    public void ReceiveNotification_WhenQueueEmpty_ReturnsNull()
    {
        // Act
        var notification = _service.ReceiveNotification();

        // Assert
        Assert.IsNull(notification);
    }

    [TestMethod]
    public void ReceiveNotification_ReturnsInFIFOOrder()
    {
        // Arrange
        _service.SendNotification("Student", "1", EntityOperation.CREATE);
        _service.SendNotification("Course", "2", EntityOperation.UPDATE);
        _service.SendNotification("Department", "3", EntityOperation.DELETE);

        // Act & Assert
        var first = _service.ReceiveNotification();
        Assert.IsNotNull(first);
        Assert.AreEqual("Student", first.EntityType);

        var second = _service.ReceiveNotification();
        Assert.IsNotNull(second);
        Assert.AreEqual("Course", second.EntityType);

        var third = _service.ReceiveNotification();
        Assert.IsNotNull(third);
        Assert.AreEqual("Department", third.EntityType);
    }

    [TestMethod]
    public void ReceiveNotification_AfterAllDequeued_ReturnsNull()
    {
        // Arrange
        _service.SendNotification("Student", "1", EntityOperation.CREATE);

        // Act
        var first = _service.ReceiveNotification();
        var second = _service.ReceiveNotification();

        // Assert
        Assert.IsNotNull(first);
        Assert.IsNull(second);
    }

    [TestMethod]
    public void SendNotification_CreateOperation_GeneratesCorrectMessage()
    {
        // Act
        _service.SendNotification("Student", "1", "John Doe", EntityOperation.CREATE);
        var notification = _service.ReceiveNotification();

        // Assert
        Assert.IsNotNull(notification);
        Assert.AreEqual("New Student 'John Doe' has been created", notification.Message);
    }

    [TestMethod]
    public void SendNotification_UpdateOperation_GeneratesCorrectMessage()
    {
        // Act
        _service.SendNotification("Course", "101", "Chemistry", EntityOperation.UPDATE);
        var notification = _service.ReceiveNotification();

        // Assert
        Assert.IsNotNull(notification);
        Assert.AreEqual("Course 'Chemistry' has been updated", notification.Message);
    }

    [TestMethod]
    public void SendNotification_DeleteOperation_GeneratesCorrectMessage()
    {
        // Act
        _service.SendNotification("Department", "5", "Engineering", EntityOperation.DELETE);
        var notification = _service.ReceiveNotification();

        // Assert
        Assert.IsNotNull(notification);
        Assert.AreEqual("Department 'Engineering' has been deleted", notification.Message);
    }

    [TestMethod]
    public void SendNotification_WithoutDisplayName_UsesIdInMessage()
    {
        // Act
        _service.SendNotification("Student", "42", EntityOperation.CREATE);
        var notification = _service.ReceiveNotification();

        // Assert
        Assert.IsNotNull(notification);
        Assert.AreEqual("New Student (ID: 42) has been created", notification.Message);
    }

    [TestMethod]
    public void MarkAsRead_DoesNotThrow()
    {
        // Act & Assert - MarkAsRead is a no-op, should not throw
        _service.MarkAsRead(1);
        _service.MarkAsRead(999);
    }

    [TestMethod]
    public void QueueCapEnforcement_ExcessItemsRemoved()
    {
        // Arrange - Send more than 500 (the cap)
        for (int i = 0; i < 510; i++)
        {
            _service.SendNotification("Test", i.ToString(), EntityOperation.CREATE);
        }

        // Act - Count remaining items by draining
        int count = 0;
        while (_service.ReceiveNotification() != null)
        {
            count++;
        }

        // Assert - Should be at most 500 (cap enforced)
        Assert.IsTrue(count <= 500, $"Expected at most 500 items but got {count}");
    }

    [TestMethod]
    public void Dispose_DoesNotThrow()
    {
        // Act & Assert
        var service = new NotificationService();
        service.Dispose();
        // Should not throw
    }

    [TestMethod]
    public void SendNotification_MultipleNotifications_AllEnqueued()
    {
        // Act
        _service.SendNotification("Student", "1", "Alice", EntityOperation.CREATE);
        _service.SendNotification("Student", "2", "Bob", EntityOperation.CREATE);

        // Assert
        var first = _service.ReceiveNotification();
        var second = _service.ReceiveNotification();
        Assert.IsNotNull(first);
        Assert.IsNotNull(second);
        Assert.IsTrue(first.Message.Contains("Alice"));
        Assert.IsTrue(second.Message.Contains("Bob"));
    }

    [TestMethod]
    public void SendNotification_WhitespaceDisplayName_UsesIdFallback()
    {
        // Act
        _service.SendNotification("Student", "1", "   ", EntityOperation.CREATE);
        var notification = _service.ReceiveNotification();

        // Assert
        Assert.IsNotNull(notification);
        Assert.AreEqual("New Student (ID: 1) has been created", notification.Message);
    }

    [TestMethod]
    public void SendNotification_EmptyDisplayName_UsesIdFallback()
    {
        // Act
        _service.SendNotification("Student", "1", "", EntityOperation.CREATE);
        var notification = _service.ReceiveNotification();

        // Assert
        Assert.IsNotNull(notification);
        Assert.AreEqual("New Student (ID: 1) has been created", notification.Message);
    }

    [TestMethod]
    public void SendNotification_NullDisplayName_UsesIdFallback()
    {
        // Act
        _service.SendNotification("Student", "1", null, EntityOperation.CREATE);
        var notification = _service.ReceiveNotification();

        // Assert
        Assert.IsNotNull(notification);
        Assert.AreEqual("New Student (ID: 1) has been created", notification.Message);
    }
}

