using Microsoft.VisualStudio.TestTools.UnitTesting;
using ContosoUniversity.Controllers;
using ContosoUniversity.Data;
using ContosoUniversity.Models;
using ContosoUniversity.Models.SchoolViewModels;
using Microsoft.AspNetCore.Mvc;
using Microsoft.EntityFrameworkCore;
using System;
using System.Collections.Generic;
using System.Linq;
using System.Net;

namespace ContosoUniversity.Tests.Controllers;

[TestClass]
public sealed class InstructorsControllerTests
{
    private SchoolContext _context = null!;
    private InstructorsController _controller = null!;

    [TestInitialize]
    public void Setup()
    {
        _context = TestDbContextFactory.Create();
        _controller = new InstructorsController(_context);
        // Drain notification queue
        var svc = new ContosoUniversity.Services.NotificationService();
        while (svc.ReceiveNotification() != null) { }
    }

    [TestCleanup]
    public void Cleanup()
    {
        _controller.Dispose();
        _context.Dispose();
    }

    private Instructor CreateTestInstructor(string firstName = "Kim", string lastName = "Abercrombie", DateTime? hireDate = null)
    {
        return new Instructor
        {
            FirstMidName = firstName,
            LastName = lastName,
            HireDate = hireDate ?? new DateTime(2000, 1, 1),
            CourseAssignments = new List<CourseAssignment>()
        };
    }

    private void SeedInstructorWithCourses()
    {
        var dept = new Department { Name = "Engineering", Budget = 350000, StartDate = new DateTime(2007, 9, 1) };
        _context.Departments.Add(dept);
        _context.SaveChanges();

        var course1 = new Course { CourseID = 1050, Title = "Chemistry", Credits = 3, DepartmentID = dept.DepartmentID };
        var course2 = new Course { CourseID = 1045, Title = "Calculus", Credits = 4, DepartmentID = dept.DepartmentID };
        _context.Courses.AddRange(course1, course2);
        _context.SaveChanges();

        var instructor = CreateTestInstructor();
        _context.Instructors.Add(instructor);
        _context.SaveChanges();

        _context.CourseAssignments.Add(new CourseAssignment { InstructorID = instructor.ID, CourseID = 1050 });
        _context.SaveChanges();

        var office = new OfficeAssignment { InstructorID = instructor.ID, Location = "Smith 17" };
        _context.OfficeAssignments.Add(office);
        _context.SaveChanges();
    }

    // ========== Index Tests ==========

    [TestMethod]
    public void Index_NoSelection_ReturnsViewWithInstructors()
    {
        // Arrange
        var instructor = CreateTestInstructor();
        _context.Instructors.Add(instructor);
        _context.SaveChanges();

        // Act
        var result = _controller.Index(null, null) as ViewResult;

        // Assert
        Assert.IsNotNull(result);
        var model = result.Model as InstructorIndexData;
        Assert.IsNotNull(model);
        Assert.IsTrue(model.Instructors.Any());
    }

    [TestMethod]
    public void Index_WithInstructorId_ShowsCourses()
    {
        // Arrange
        SeedInstructorWithCourses();
        var instructorId = _context.Instructors.First().ID;

        // Act
        var result = _controller.Index(instructorId, null) as ViewResult;

        // Assert
        Assert.IsNotNull(result);
        var model = result.Model as InstructorIndexData;
        Assert.IsNotNull(model);
        Assert.IsNotNull(model.Courses);
        Assert.IsTrue(model.Courses.Any());
    }

