    public void Delete_GET_NotFound_ReturnsNotFound()
    {
        // Act
        var result = _controller.Delete(999) as NotFoundResult;

        // Assert
        Assert.IsNotNull(result);
    }

    // ========== DeleteConfirmed Tests ==========

    [TestMethod]
    public void DeleteConfirmed_ValidId_RemovesInstructorAndRedirects()
    {
        // Arrange
        var instructor = CreateTestInstructor("ToDelete", "Instructor");
        instructor.CourseAssignments = new List<CourseAssignment>();
        _context.Instructors.Add(instructor);
        _context.SaveChanges();

        // Act
        var result = _controller.DeleteConfirmed(instructor.ID) as RedirectToActionResult;

        // Assert
        Assert.IsNotNull(result);
        Assert.AreEqual("Index", result.ActionName);
        Assert.IsNull(_context.Instructors.Find(instructor.ID));
    }

    [TestMethod]
    public void DeleteConfirmed_InstructorAdminOfDepartment_ClearsDepartmentAdmin()
    {
        // Arrange
        var instructor = CreateTestInstructor("Admin", "Instructor");
        instructor.CourseAssignments = new List<CourseAssignment>();
        _context.Instructors.Add(instructor);
        _context.SaveChanges();

        var dept = new Department
        {
            Name = "TestDept",
            Budget = 100000,
            StartDate = DateTime.Now,
            InstructorID = instructor.ID
        };
        _context.Departments.Add(dept);
        _context.SaveChanges();

        // Act
        _controller.DeleteConfirmed(instructor.ID);

        // Assert
        var updatedDept = _context.Departments.Find(dept.DepartmentID);
        Assert.IsNotNull(updatedDept);
        Assert.IsNull(updatedDept.InstructorID);
    }
}

