    public void About_SingleStudent_ReturnsSingleGroup()
    {
        // Arrange
        _context.Students.Add(new Student
        {
            FirstMidName = "Only",
            LastName = "Student",
            EnrollmentDate = new DateTime(2021, 1, 15)
        });
        _context.SaveChanges();

        // Act
        var result = _controller.About() as ViewResult;

        // Assert
        Assert.IsNotNull(result);
        var model = result.Model as List<EnrollmentDateGroup>;
        Assert.IsNotNull(model);
        Assert.AreEqual(1, model.Count);
        Assert.AreEqual(1, model[0].StudentCount);
        Assert.AreEqual(new DateTime(2021, 1, 15), model[0].EnrollmentDate);
    }

