using Microsoft.VisualStudio.TestTools.UnitTesting;
using ContosoUniversity.Data;
using ContosoUniversity.Models;
using Microsoft.EntityFrameworkCore;
using System;
using System.Linq;

namespace ContosoUniversity.Tests.Data;

[TestClass]
public sealed class SchoolContextTests
{
    [TestMethod]
    public void SchoolContext_CanCreateInMemory()
    {
        // Arrange & Act
        using var context = TestDbContextFactory.Create();

        // Assert
        Assert.IsNotNull(context);
        Assert.IsNotNull(context.Students);
        Assert.IsNotNull(context.Instructors);
        Assert.IsNotNull(context.Courses);
        Assert.IsNotNull(context.Departments);
        Assert.IsNotNull(context.Enrollments);
        Assert.IsNotNull(context.CourseAssignments);
        Assert.IsNotNull(context.OfficeAssignments);
        Assert.IsNotNull(context.People);
        Assert.IsNotNull(context.Notifications);
    }

    [TestMethod]
    public void SchoolContext_CanAddAndRetrieveStudent()
    {
        // Arrange
        using var context = TestDbContextFactory.Create();
        var student = new Student
        {
            FirstMidName = "Test",
            LastName = "Student",
            EnrollmentDate = new DateTime(2023, 9, 1)
        };

        // Act
        context.Students.Add(student);
        context.SaveChanges();

        // Assert
        var retrieved = context.Students.First();
        Assert.AreEqual("Test", retrieved.FirstMidName);
        Assert.AreEqual("Student", retrieved.LastName);
    }

    [TestMethod]
    public void SchoolContext_CanAddInstructor()
    {
        // Arrange
        using var context = TestDbContextFactory.Create();
        var instructor = new Instructor
        {
            FirstMidName = "Test",
            LastName = "Instructor",
            HireDate = new DateTime(2020, 1, 1)
        };

        // Act
        context.Instructors.Add(instructor);
        context.SaveChanges();

        // Assert
        var retrieved = context.Instructors.First();
        Assert.AreEqual("Test", retrieved.FirstMidName);
        Assert.AreEqual("Instructor", retrieved.LastName);
    }

    [TestMethod]
    public void SchoolContext_CourseAssignment_CompositeKey()
    {
        // Arrange
        using var context = TestDbContextFactory.Create();

        var instructor = new Instructor { FirstMidName = "Jane", LastName = "Doe", HireDate = DateTime.Now };
        context.Instructors.Add(instructor);
        context.SaveChanges();

        var dept = new Department { Name = "Test", Budget = 100000, StartDate = DateTime.Now };
        context.Departments.Add(dept);
        context.SaveChanges();

        var course = new Course { CourseID = 5001, Title = "Test", Credits = 3, DepartmentID = dept.DepartmentID };
        context.Courses.Add(course);
        context.SaveChanges();

        var assignment = new CourseAssignment { CourseID = course.CourseID, InstructorID = instructor.ID };
        context.CourseAssignments.Add(assignment);
        context.SaveChanges();

        // Act
        var retrieved = context.CourseAssignments.First();

        // Assert
        Assert.AreEqual(course.CourseID, retrieved.CourseID);
        Assert.AreEqual(instructor.ID, retrieved.InstructorID);
    }

    [TestMethod]
    public void SchoolContext_CanAddDepartmentWithInstructor()
    {
        // Arrange
        using var context = TestDbContextFactory.Create();

        var instructor = new Instructor { FirstMidName = "Admin", LastName = "Person", HireDate = DateTime.Now };
        context.Instructors.Add(instructor);
        context.SaveChanges();

        var dept = new Department
        {
            Name = "Engineering",
            Budget = 350000,
            StartDate = new DateTime(2007, 9, 1),
            InstructorID = instructor.ID
        };

        // Act
        context.Departments.Add(dept);
        context.SaveChanges();

        // Assert
        var retrieved = context.Departments.Include(d => d.Administrator).First();
        Assert.AreEqual("Engineering", retrieved.Name);
        Assert.AreEqual(350000m, retrieved.Budget);
        Assert.AreEqual(instructor.ID, retrieved.InstructorID);
    }

    [TestMethod]
    public void SchoolContext_CanAddNotification()
    {
        // Arrange
        using var context = TestDbContextFactory.Create();
        var notification = new Notification
        {
            EntityType = "Student",
            EntityId = "1",
            Operation = "CREATE",
            Message = "Student created",
            CreatedAt = DateTime.Now,
            CreatedBy = "System",
            IsRead = false
        };

        // Act
        context.Notifications.Add(notification);
        context.SaveChanges();

        // Assert
        var retrieved = context.Notifications.First();
        Assert.AreEqual("Student", retrieved.EntityType);
        Assert.AreEqual("1", retrieved.EntityId);
        Assert.AreEqual("CREATE", retrieved.Operation);
        Assert.AreEqual("Student created", retrieved.Message);
        Assert.IsFalse(retrieved.IsRead);
    }

    [TestMethod]
    public void SchoolContext_CanAddEnrollmentWithGrade()
    {
        // Arrange
        using var context = TestDbContextFactory.Create();

        var student = new Student { FirstMidName = "Test", LastName = "Student", EnrollmentDate = DateTime.Now };
        context.Students.Add(student);
        context.SaveChanges();

        var dept = new Department { Name = "Test", Budget = 100000, StartDate = DateTime.Now };
        context.Departments.Add(dept);
        context.SaveChanges();

        var course = new Course { CourseID = 9001, Title = "Test Course", Credits = 3, DepartmentID = dept.DepartmentID };
        context.Courses.Add(course);
        context.SaveChanges();

        var enrollment = new Enrollment
        {
            StudentID = student.ID,
            CourseID = course.CourseID,
            Grade = Grade.A
        };

        // Act
        context.Enrollments.Add(enrollment);
        context.SaveChanges();

        // Assert
        var retrieved = context.Enrollments.First();
        Assert.AreEqual(Grade.A, retrieved.Grade);
        Assert.AreEqual(student.ID, retrieved.StudentID);
        Assert.AreEqual(course.CourseID, retrieved.CourseID);
    }

    [TestMethod]
    public void SchoolContext_CanAddOfficeAssignment()
    {
        // Arrange
        using var context = TestDbContextFactory.Create();

        var instructor = new Instructor { FirstMidName = "Office", LastName = "Person", HireDate = DateTime.Now };
        context.Instructors.Add(instructor);
        context.SaveChanges();

        var office = new OfficeAssignment { InstructorID = instructor.ID, Location = "Room 101" };

        // Act
        context.OfficeAssignments.Add(office);
        context.SaveChanges();

        // Assert
        var retrieved = context.OfficeAssignments.First();
        Assert.AreEqual("Room 101", retrieved.Location);
        Assert.AreEqual(instructor.ID, retrieved.InstructorID);
    }
}

